import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X, MapPin } from 'lucide-react';

function LocationMarker({ position, setPosition }) {
  useMapEvents({ click(e) { setPosition([e.latlng.lat, e.latlng.lng]); } });
  return position ? <Marker position={position} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [nombre, setNombre] = useState('');
  const [direccion, setDireccion] = useState('');
  const [provincia, setProvincia] = useState('Tucumán');
  const [ciudad, setCiudad] = useState('');
  const [zona, setZona] = useState('');
  const [coords, setCoords] = useState([-26.816, -65.216]);

  const ubicacionesData = {
    'Tucumán': {
      'San Miguel de Tucumán': ['Centro', 'Barrio Norte', 'Barrio Sur', 'Villa Luján'],
      'Yerba Buena': ['Casco Viejo', 'San José', 'Cerca del Shopping', 'Av. Perón'],
      'Tafí Viejo': ['Centro', 'Lomas de Tafí', 'Villa Mitre']
    },
    'Salta': {
      'Salta Capital': ['Centro', 'Tres Cerritos'],
      'Cafayate': ['Centro']
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if(!ciudad || !zona) return alert("Selecciona ciudad y zona");
    onSave({ nombre, direccion, provincia, ciudad, zona, coords });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px' }}>
          <h3>Nueva Sucursal</h3>
          <X onClick={onClose} style={{ cursor: 'pointer' }} />
        </div>
        <form onSubmit={handleSubmit}>
          <input placeholder="Nombre" style={inputStyle} required value={nombre} onChange={e => setNombre(e.target.value)} />
          
          <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
            <select style={inputStyle} value={provincia} onChange={e => {setProvincia(e.target.value); setCiudad('');}}>
              {Object.keys(ubicacionesData).map(p => <option key={p} value={p}>{p}</option>)}
            </select>
            <select style={inputStyle} required value={ciudad} onChange={e => {setCiudad(e.target.value); setZona('');}}>
              <option value="">Ciudad</option>
              {Object.keys(ubicacionesData[provincia]).map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>

          <select style={{...inputStyle, marginBottom: '10px'}} required value={zona} onChange={e => setZona(e.target.value)}>
            <option value="">Zona / Barrio</option>
            {(ubicacionesData[provincia][ciudad] || []).map(z => <option key={z} value={z}>{z}</option>)}
          </select>

          <input placeholder="Dirección" style={inputStyle} required value={direccion} onChange={e => setDireccion(e.target.value)} />
          
          <div style={{ height: '150px', margin: '10px 0', borderRadius: '8px', overflow: 'hidden' }}>
            <MapContainer center={coords} zoom={13} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationMarker position={coords} setPosition={setCoords} />
            </MapContainer>
          </div>
          <button type="submit" style={btnSubmitModal}>Guardar Sucursal</button>
        </form>
      </div>
    </div>
  );
};

const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(0,0,0,0.6)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000 };
const modalContent = { background: 'white', padding: '25px', borderRadius: '15px', width: '400px' };
const inputStyle = { width: '100%', padding: '10px', marginBottom: '5px', borderRadius: '8px', border: '1px solid #ddd', boxSizing: 'border-box' };
const btnSubmitModal = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer', marginTop: '10px' };

export default ModalNuevaSucursal;
